import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface NextEvent {
  title: string;
  time: string;
  location: string;
}

interface CalendarData {
  todayDate: string;
  eventsCount: number;
  nextEvent: NextEvent;
}

export default function Widget() {
  const calendarData = response.data as CalendarData;
  const { todayDate, eventsCount, nextEvent } = calendarData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 280, maxWidth: 380, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Today's Date
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              {todayDate}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Number of Events
            </Typography>
            <Typography variant="h5" fontWeight={500} sx={{ color: '#FFC107' }}>
              {eventsCount}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Next Event
            </Typography>
            <Stack spacing={0.5}>
              <Typography variant="body1" fontWeight={600} sx={{ color: '#333' }}>
                {nextEvent.title}
              </Typography>
              <Stack direction="row" spacing={0.5}>
                <Chip label={nextEvent.time} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
                <Chip label={nextEvent.location} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
              </Stack>
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
